SELECT COUNT(*) as removidos_existem FROM establishments WHERE id IN (2051, 7709, 7072, 1536, 5856, 5027, 3038, 4555, 7184, 797, 3999);

-- Verificar que os bairros foram corrigidos
SELECT id, name, neighborhood FROM establishments WHERE id IN (1820, 6529, 5609, 5438, 5981);

-- Contar total de registros ativos e pendentes
SELECT status, COUNT(*) as total FROM establishments GROUP BY status;

